# Category: outdated_dependencies

#!/usr/bin/env python3
import os
import sys
import subprocess
import tempfile
import time
import zipfile
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parent
REQUIREMENTS = PROJECT_ROOT / "requirements.txt"
PACKAGE_NAME = f"{PROJECT_ROOT.name}-{int(time.time())}.zip"
EXCLUDE_DIRS = {
    ".git",
    ".github",
    "__pycache__",
    ".pytest_cache",
    "venv",
    ".venv",
    "dist",
    "build",
    ".mypy_cache",
}
EXCLUDE_FILES = {".DS_Store"}


def run(cmd, **kwargs):
    print("+", *cmd)
    subprocess.check_call(cmd, **kwargs)


def install_deps():
    if REQUIREMENTS.exists():
        run([sys.executable, "-m", "pip", "install", "-r", str(REQUIREMENTS), "--quiet"])
    else:
        print("No requirements.txt found; skipping dependency installation.")


def run_tests():
    try:
        run([sys.executable, "-m", "pytest", "-q"])
    except FileNotFoundError:
        print("pytest not installed; attempting to install it.")
        run([sys.executable, "-m", "pip", "install", "pytest", "--quiet"])
        run([sys.executable, "-m", "pytest", "-q"])


def should_include(path: Path) -> bool:
    parts = set(path.parts)
    if parts & EXCLUDE_DIRS:
        return False
    if path.name in EXCLUDE_FILES:
        return False
    if path.suffix == ".pyc":
        return False
    return True


def package_project():
    with tempfile.TemporaryDirectory() as tmpdir:
        zip_path = Path(tmpdir) / PACKAGE_NAME
        with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zf:
            for file in PROJECT_ROOT.rglob("*"):
                if not should_include(file.relative_to(PROJECT_ROOT)):
                    continue
                if file.is_file():
                    zf.write(file, file.relative_to(PROJECT_ROOT))
        final_path = PROJECT_ROOT / "dist"
        final_path.mkdir(exist_ok=True)
        packaged = final_path / PACKAGE_NAME
        zip_path.replace(packaged)
        print(f"Packaged deployment artifact: {packaged}")


def main():
    os.chdir(PROJECT_ROOT)
    install_deps()
    run_tests()
    package_project()


if __name__ == "__main__":
    main()